import OpenAI, { toFile } from "openai";
import {
  INFOGRAPHIC_STYLES,
  INFOGRAPHIC_LANGUAGES,
  type InfographicStyle,
  type InfographicLanguage,
} from "./infographicStyles";

const apiKey = process.env.OPENAI_API_KEY;
if (!apiKey) {
  throw new Error("OPENAI_API_KEY is not set in environment");
}

// OpenAI's GPT Image models. Image generation + editing both go through the
// Images API (openai.images.edit), which accepts one or more reference images
// plus a text prompt and returns a base64-encoded PNG.
export const openai = new OpenAI({ apiKey });

// GPT Image 2 is the default. Override with OPENAI_IMAGE_MODEL in the
// environment (e.g. "gpt-image-2-2026-04-21" or "gpt-image-1") if needed.
export const IMAGE_MODEL = process.env.OPENAI_IMAGE_MODEL ?? "gpt-image-2";
export const INFOGRAPHIC_MODEL = IMAGE_MODEL;
/** Cheap text+vision model used for the pre-pass product analysis. */
export const VISION_MODEL = process.env.OPENAI_VISION_MODEL ?? "gpt-4o-mini";

export type Turn = {
  role: "user" | "model";
  text?: string;
  imageBase64?: string;
  imageMimeType?: string;
};

export type EditResult = {
  imageBase64: string;
  mimeType: string;
  text?: string;
};

export type InlineImage = {
  base64: string;
  mimeType: string;
};

export type InfographicAspect = "1:1" | "3:4" | "4:3" | "9:16" | "16:9";

export {
  INFOGRAPHIC_STYLES,
  INFOGRAPHIC_LANGUAGES,
  type InfographicStyle,
  type InfographicLanguage,
};

export type InfographicInput = {
  images: InlineImage[];
  description?: string;
  aspectRatio?: InfographicAspect;
  style?: InfographicStyle;
  language?: InfographicLanguage;
};

/** Decode a base64 inline image into an Uploadable file for the Images API. */
async function inlineToFile(
  base64: string,
  mimeType: string,
  filename: string,
) {
  return toFile(Buffer.from(base64, "base64"), filename, { type: mimeType });
}

/** Map an InfographicAspect onto the closest size GPT Image supports. */
function aspectToSize(
  aspect: InfographicAspect,
): "1024x1024" | "1536x1024" | "1024x1536" {
  switch (aspect) {
    case "1:1":
      return "1024x1024";
    case "4:3":
    case "16:9":
      return "1536x1024";
    case "3:4":
    case "9:16":
    default:
      return "1024x1536";
  }
}

function extractImage(response: OpenAI.Images.ImagesResponse): EditResult {
  const imageBase64 = response.data?.[0]?.b64_json;
  if (!imageBase64) {
    throw new Error(
      "GPT Image returned no image (likely blocked by the moderation filter).",
    );
  }
  return { imageBase64, mimeType: "image/png" };
}

const PRODUCT_ANALYSIS_PROMPT = [
  "Look at the attached product photo(s) and output a SHORT factual list of",
  "the product's hard-to-render details that downstream image generation",
  "must preserve. Keep the output under 120 words total. Focus only on:",
  "",
  "1. PRINTED TEXT — every word, slogan, label visible on the product,",
  "   transcribed VERBATIM with exact spelling and capitalization, plus its",
  "   position (e.g. 'MY FRIEND' centered on chest, 'EAU DE PARFUM' on bottle",
  "   label).",
  "2. PRINTED GRAPHICS — every illustration, character, logo, or pattern.",
  "   One brief sentence each: subject + colors + position.",
  "3. EMBROIDERED / 3D / APPLIQUE elements — patches, raised motifs, fluffy",
  "   decorations. One brief line each.",
  "4. ANY DISTINCTIVE DETAIL the image generator might miss or fabricate",
  "   wrong (e.g. a specific stitch pattern, a unique closure, a small",
  "   side label).",
  "",
  "Skip generic info that's already obvious from the photo (product type,",
  "color, material, hardware count). Be brief, factual, and focused only",
  "on details that need to be preserved character-for-character.",
].join("\n");

/** Keep the analysis text small so the downstream image-gen request fits
 * comfortably under Vertex's payload threshold. */
const MAX_ANALYSIS_CHARS = 1200;

/**
 * Vision pre-pass: extract a precise text description of the product from
 * the uploaded reference photo(s). The output is fed into the image-gen
 * call as a second source of truth alongside the photos themselves, which
 * helps the image model preserve specific prints, graphics, and hardware
 * that it might otherwise drop or reinterpret.
 *
 * Uses a cheap text+vision model (~$0.0001 / call), so the pre-pass adds
 * negligible cost.
 */
export async function describeProduct(images: InlineImage[]): Promise<string> {
  if (images.length === 0) return "";

  const content: OpenAI.Chat.Completions.ChatCompletionContentPart[] =
    images.map((img) => ({
      type: "image_url",
      image_url: { url: `data:${img.mimeType};base64,${img.base64}` },
    }));
  content.push({ type: "text", text: PRODUCT_ANALYSIS_PROMPT });

  const response = await openai.chat.completions.create({
    model: VISION_MODEL,
    messages: [{ role: "user", content }],
  });

  let text = (response.choices[0]?.message?.content ?? "").trim();
  if (text.length > MAX_ANALYSIS_CHARS) {
    text = text.slice(0, MAX_ANALYSIS_CHARS) + "…";
  }
  return text;
}

const COPY_LANGUAGE_NAME: Record<InfographicLanguage, string> = {
  en: "English",
  ru: "Russian (Cyrillic script)",
  uz: "Uzbek (Latin alphabet)",
};

function buildProductCopyPrompt(
  language: InfographicLanguage,
  description: string,
): string {
  const hasDescription = description.length > 0;
  return [
    "You are a marketplace copywriter. Look at the attached product photo(s)",
    hasDescription ? "and the seller's product description below," : "",
    "and produce the EXACT short marketing copy that will be printed on a",
    "single product infographic card. Every value must be SPECIFIC to THIS",
    "product as seen in the photo — never a generic placeholder.",
    "",
    `Write every copy VALUE in ${COPY_LANGUAGE_NAME[language]}. Do not use any`,
    "other language for the values (numbers and universal symbols are fine).",
    "",
    "Return PLAIN TEXT with exactly these labels, one per line, value after",
    "the colon. Keep each value as tight as a real card label. If a field",
    "cannot be determined, give a confident best guess from the photo — never",
    "leave a placeholder like '__', 'TODO', or 'N/A' (except SIZES, which may",
    "be 'n/a').",
    "",
    "CATEGORY: the product category in 1 short word (the giant headline word).",
    "PRODUCT_NAME: a short 1-4 word product or model name.",
    "MATERIAL: the main material / composition (a fabric/material name, with a",
    "  percentage only if visible or stated).",
    "FIT: fit or silhouette in 1-2 words (e.g. relaxed, tailored, oversized);",
    "  for non-apparel, the form factor instead.",
    "COLORWAY: the dominant colorway name(s), 1-2 words each, comma separated.",
    "SIZES: a size range if apparent or stated, otherwise 'n/a'.",
    "SELLING_POINTS: 3 to 5 very short benefit phrases (2-4 words each),",
    "  separated by ' | ', specific to this product.",
    "",
    hasDescription ? "Seller's product description:" : "",
    hasDescription ? '"""' : "",
    hasDescription ? description : "",
    hasDescription ? '"""' : "",
  ]
    .filter(Boolean)
    .join("\n");
}

// Vision copy pre-pass: reads the reference photo(s) (plus the optional
// seller description) and returns product-specific on-image copy. Injected
// into the image prompt so the model renders text derived from THIS product
// instead of the format examples baked into each style template.
export async function extractProductCopy(
  images: InlineImage[],
  description: string,
  language: InfographicLanguage,
): Promise<string> {
  if (images.length === 0) return "";

  const content: OpenAI.Chat.Completions.ChatCompletionContentPart[] =
    images.map((img) => ({
      type: "image_url",
      image_url: { url: `data:${img.mimeType};base64,${img.base64}` },
    }));
  content.push({
    type: "text",
    text: buildProductCopyPrompt(language, description),
  });

  const response = await openai.chat.completions.create({
    model: VISION_MODEL,
    messages: [{ role: "user", content }],
  });

  let text = (response.choices[0]?.message?.content ?? "").trim();
  if (text.length > MAX_ANALYSIS_CHARS) {
    text = text.slice(0, MAX_ANALYSIS_CHARS) + "…";
  }
  return text;
}

export async function editImage(turns: Turn[]): Promise<EditResult> {
  // The Images API is stateless, so prior turns aren't replayed as a chat.
  // The client always sends the current canvas + the new instruction as the
  // final turn, so we edit the most recent image with the most recent text.
  const lastImageTurn = [...turns].reverse().find((t) => t.imageBase64);
  if (!lastImageTurn?.imageBase64) {
    throw new Error("No image was provided to edit.");
  }
  const prompt = turns[turns.length - 1]?.text ?? lastImageTurn.text ?? "";

  const image = await inlineToFile(
    lastImageTurn.imageBase64,
    lastImageTurn.imageMimeType ?? "image/png",
    "image.png",
  );

  const response = await openai.images.edit({
    model: IMAGE_MODEL,
    image,
    prompt,
    size: "auto",
    quality: "high",
  });

  return extractImage(response);
}

